import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Question {
  id: string;
  text: string;
  correctAnswer: boolean; // true for 'صح', false for 'غلط'
  userAnswer?: boolean;
}

export type AppState = 'input' | 'quiz' | 'result';

import { Question } from '../types';

export const parseRawText = (text: string): Question[] => {
  // Pattern: [Statement] followed by "الإجابة: صح" or "الإجابة: غلط"
  const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 0);
  const questions: Question[] = [];

  let currentQuestionText = "";

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    if (line.includes("الإجابة:")) {
      const isCorrect = line.includes("صح");
      if (currentQuestionText) {
        questions.push({
          id: Math.random().toString(36).substr(2, 9),
          text: currentQuestionText,
          correctAnswer: isCorrect
        });
        currentQuestionText = "";
      }
    } else {
      // If it doesn't contain the answer keyword, it's part of the question text
      currentQuestionText += (currentQuestionText ? " " : "") + line;
    }
  }

  return questions;
};

import React, { useState, useCallback } from 'react';
import { parseRawText } from './services/parserService';
import { Question, AppState } from './types';
import ParserView from './components/ParserView';
import QuizView from './components/QuizView';
import ResultView from './components/ResultView';

const App: React.FC = () => {
  const [view, setView] = useState<AppState>('input');
  const [questions, setQuestions] = useState<Question[]>([]);
  const [score, setScore] = useState(0);

  const handleGenerate = (text: string) => {
    const parsed = parseRawText(text);
    if (parsed.length > 0) {
      setQuestions(parsed);
      setView('quiz');
    } else {
      alert("لم نتمكن من العثور على أسئلة صالحة. تأكد من وجود 'الإجابة: صح' أو 'الإجابة: غلط' بعد كل عبارة.");
    }
  };

  const handleSubmitQuiz = (updatedQuestions: Question[]) => {
    setQuestions(updatedQuestions);
    const correctCount = updatedQuestions.filter(q => q.userAnswer === q.correctAnswer).length;
    setScore(correctCount);
    setView('result');
  };

  const handleReset = () => {
    setQuestions([]);
    setScore(0);
    setView('input');
  };

  const handleRetake = () => {
    const resetQuestions = questions.map(q => ({ ...q, userAnswer: undefined }));
    setQuestions(resetQuestions);
    setScore(0);
    setView('quiz');
  };

  return (
    <div className="min-h-screen pb-12">
      {/* Decorative Top Banner */}
      <div className="h-4 bg-indigo-700 w-full mb-8"></div>

      <main className="max-w-3xl mx-auto px-4">
        {view === 'input' && (
          <ParserView onGenerate={handleGenerate} />
        )}

        {view === 'quiz' && (
          <QuizView 
            questions={questions} 
            onSubmit={handleSubmitQuiz} 
            onBack={handleReset} 
          />
        )}

        {view === 'result' && (
          <ResultView 
            questions={questions} 
            score={score} 
            onReset={handleReset} 
            onRetake={handleRetake} 
          />
        )}
      </main>
    </div>
  );
};

export default App;

