import React, { useState } from 'react';
import { Question } from '../types';

interface QuizViewProps {
  questions: Question[];
  onSubmit: (questions: Question[]) => void;
  onBack: () => void;
}

const QuizView: React.FC<QuizViewProps> = ({ questions, onSubmit, onBack }) => {
  const [answers, setAnswers] = useState<{ [key: string]: boolean }>(
    Object.fromEntries(questions.filter(q => q.userAnswer !== undefined).map(q => [q.id, q.userAnswer!]))
  );

  const handleSelect = (questionId: string, value: boolean) => {
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const isComplete = Object.keys(answers).length === questions.length;

  const handleSubmit = () => {
    const finalQuestions = questions.map(q => ({
      ...q,
      userAnswer: answers[q.id]
    }));
    onSubmit(finalQuestions);
  };

  return (
    <div className="space-y-4">
      <div className="bg-white rounded-xl shadow-sm border-t-8 border-indigo-700 p-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">اختبار الزيادة السكانية في مصر</h1>
        <p className="text-gray-600 mb-4 text-sm">* مطلوب</p>
        <button 
          onClick={onBack}
          className="text-indigo-700 text-sm font-semibold hover:underline"
        >
          &larr; العودة لتعديل الأسئلة
        </button>
      </div>

      {questions.map((q, idx) => (
        <div key={q.id} className="bg-white rounded-xl shadow-sm p-6 border border-gray-200 transition-all hover:shadow-md">
          <p className="text-lg font-medium text-gray-900 mb-6 leading-relaxed">
            {idx + 1}. {q.text} <span className="text-red-500">*</span>
          </p>

          <div className="space-y-3">
            <label className="flex items-center group cursor-pointer p-2 rounded-lg hover:bg-gray-50">
              <input
                type="radio"
                name={`question-${q.id}`}
                checked={answers[q.id] === true}
                onChange={() => handleSelect(q.id, true)}
                className="w-5 h-5 text-indigo-600 border-gray-300 focus:ring-indigo-500"
              />
              <span className="mr-3 text-gray-700 font-medium">صح</span>
            </label>

            <label className="flex items-center group cursor-pointer p-2 rounded-lg hover:bg-gray-50">
              <input
                type="radio"
                name={`question-${q.id}`}
                checked={answers[q.id] === false}
                onChange={() => handleSelect(q.id, false)}
                className="w-5 h-5 text-indigo-600 border-gray-300 focus:ring-indigo-500"
              />
              <span className="mr-3 text-gray-700 font-medium">غلط</span>
            </label>
          </div>
        </div>
      ))}

      <div className="flex justify-between items-center pt-6">
        <button
          onClick={handleSubmit}
          disabled={!isComplete}
          className="bg-indigo-700 text-white font-bold py-2 px-8 rounded-lg hover:bg-indigo-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-md"
        >
          إرسال
        </button>
        <div className="text-gray-500 text-sm">
           {Object.keys(answers).length} من {questions.length} تم الإجابة عليها
        </div>
      </div>
    </div>
  );
};

