export type QuestionType = 'boolean' | 'multiple';

export interface Question {
  id: string;
  text: string;
  type: QuestionType;
  options?: string[]; // Only for multiple choice
  correctAnswer: string; // 'صح', 'غلط' or 'أ', 'ب', 'ج', 'د'
  userAnswer?: string;
}

export type AppState = 'input' | 'quiz' | 'result';

import { Question, QuestionType } from '../types';

export const parseRawText = (text: string): Question[] => {
  const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 0);
  const questions: Question[] = [];

  let currentText = "";
  let currentOptions: string[] = [];

  // Prefixes for multiple choice options
  const optionPrefixes = ['أ.', 'ب.', 'ج.', 'د.', 'أ)', 'ب)', 'ج)', 'د)'];

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // Check if line is an answer line
    if (line.startsWith("الإجابة:")) {
      const answerPart = line.replace("الإجابة:", "").trim();
      // Extract the core answer (e.g., from "ب)" or "ب." or "صح" get just the key)
      let finalAnswer = answerPart;
      if (answerPart.length > 1 && (answerPart.includes('.') || answerPart.includes(')'))) {
        finalAnswer = answerPart[0];
      } else if (answerPart.startsWith('صح')) {
        finalAnswer = 'صح';
      } else if (answerPart.startsWith('غلط')) {
        finalAnswer = 'غلط';
      } else {
        finalAnswer = answerPart[0]; // Fallback to first char (أ, ب, ج, د)
      }

      if (currentText) {
        const type: QuestionType = currentOptions.length > 0 ? 'multiple' : 'boolean';
        questions.push({
          id: Math.random().toString(36).substr(2, 9),
          text: currentText,
          type: type,
          options: currentOptions.length > 0 ? currentOptions : undefined,
          correctAnswer: finalAnswer
        });

        // Reset for next question
        currentText = "";
        currentOptions = [];
      }
    } 
    // Check if line is an option
    else if (optionPrefixes.some(prefix => line.startsWith(prefix))) {
      currentOptions.push(line);
    } 
    // Otherwise, it's part of the question text
    else {
      if (currentOptions.length > 0) {
        // If we already have options but find a new text line, it might be a multi-line question or a mistake.
        // For simplicity, we'll append to the last option if it's not a new question.
        currentOptions[currentOptions.length - 1] += " " + line;
      } else {
        currentText += (currentText ? " " : "") + line;
      }
    }
  }

  return questions;
};

import React, { useState } from 'react';
import { Question } from '../types';

interface QuizViewProps {
  questions: Question[];
  onSubmit: (questions: Question[]) => void;
  onBack: () => void;
}

const QuizView: React.FC<QuizViewProps> = ({ questions, onSubmit, onBack }) => {
  const [answers, setAnswers] = useState<{ [key: string]: string }>(
    Object.fromEntries(questions.filter(q => q.userAnswer !== undefined).map(q => [q.id, q.userAnswer!]))
  );

  const handleSelect = (questionId: string, value: string) => {
    setAnswers(prev => ({ ...prev, [questionId]: value }));
  };

  const isComplete = Object.keys(answers).length === questions.length;

  const handleSubmit = () => {
    const finalQuestions = questions.map(q => ({
      ...q,
      userAnswer: answers[q.id]
    }));
    onSubmit(finalQuestions);
  };

  return (
    <div className="space-y-4">
      <div className="bg-white rounded-xl shadow-sm border-t-8 border-indigo-700 p-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">الاختبار التفاعلي</h1>
        <p className="text-gray-600 mb-4 text-sm">* مطلوب</p>
        <button 
          onClick={onBack}
          className="text-indigo-700 text-sm font-semibold hover:underline"
        >
          &larr; العودة لتعديل الأسئلة
        </button>
      </div>

      {questions.map((q, idx) => (
        <div key={q.id} className="bg-white rounded-xl shadow-sm p-6 border border-gray-200 transition-all hover:shadow-md">
          <p className="text-lg font-medium text-gray-900 mb-6 leading-relaxed">
            {idx + 1}. {q.text} <span className="text-red-500">*</span>
          </p>

          <div className="space-y-3">
            {q.type === 'boolean' ? (
              <>
                {['صح', 'غلط'].map((option) => (
                  <label key={option} className="flex items-center group cursor-pointer p-3 rounded-lg hover:bg-indigo-50 transition-colors border border-transparent hover:border-indigo-100">
                    <input
                      type="radio"
                      name={`question-${q.id}`}
                      checked={answers[q.id] === option}
                      onChange={() => handleSelect(q.id, option)}
                      className="w-5 h-5 text-indigo-600 border-gray-300 focus:ring-indigo-500"
                    />
                    <span className="mr-3 text-gray-700 font-medium">{option}</span>
                  </label>
                ))}
              </>
            ) : (
              <>
                {q.options?.map((optionText) => {
                  const optionKey = optionText[0]; // Gets أ or ب or ج or د
                  return (
                    <label key={optionText} className="flex items-center group cursor-pointer p-3 rounded-lg hover:bg-indigo-50 transition-colors border border-transparent hover:border-indigo-100">
                      <input
                        type="radio"
                        name={`question-${q.id}`}
                        checked={answers[q.id] === optionKey}
                        onChange={() => handleSelect(q.id, optionKey)}
                        className="w-5 h-5 text-indigo-600 border-gray-300 focus:ring-indigo-500"
                      />
                      <span className="mr-3 text-gray-700">{optionText}</span>
                    </label>
                  );
                })}
              </>
            )}
          </div>
        </div>
      ))}

      <div className="flex justify-between items-center pt-6 pb-10">
        <button
          onClick={handleSubmit}
          disabled={!isComplete}
          className="bg-indigo-700 text-white font-bold py-3 px-12 rounded-lg hover:bg-indigo-800 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-lg"
        >
          إرسال الإجابات
        </button>
        <div className="text-gray-500 text-sm font-semibold">
           تمت الإجابة على {Object.keys(answers).length} من أصل {questions.length}
        </div>
      </div>
    </div>
  );
};

export default QuizView;

import React from 'react';
import { Question } from '../types';

interface ResultViewProps {
  questions: Question[];
  score: number;
  onReset: () => void;
  onRetake: () => void;
}

const ResultView: React.FC<ResultViewProps> = ({ questions, score, onReset, onRetake }) => {
  const percentage = Math.round((score / questions.length) * 100);

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-xl shadow-sm border-t-8 border-indigo-700 p-8 text-center">
        <h1 className="text-3xl font-bold text-gray-900 mb-4">نتائج الاختبار</h1>
        <div className="mb-6">
          <p className="text-gray-500 mb-1">الدرجة النهائية</p>
          <span className="text-6xl font-extrabold text-indigo-700">{score}</span>
          <span className="text-2xl text-gray-400"> / {questions.length}</span>
        </div>
        <div className="w-full bg-gray-200 rounded-full h-4 mb-8 overflow-hidden">
          <div 
